// Tweet-count event — politics template with data-driven probability estimates
// Data: 109 tweets in ~85.7 hours elapsed, 82.3h remaining
// Rate: 109/85.7 ≈ 1.272 tweets/hr → projected additional: 1.272 * 82.3 ≈ 104.7
// Expected total: ~213.7

const THRESHOLD = 0.04;

// Normal CDF approximation for range probabilities
const normCDF = ctx.helpers.normCDF;

// Model parameters
const elapsed = (ctx.timing.nowTs - new Date("2026-04-17T16:00:00Z").getTime()) / 3600000;
const totalWindow = (new Date("2026-04-24T16:00:00Z").getTime() - new Date("2026-04-17T16:00:00Z").getTime()) / 3600000;
const hoursRemaining = totalWindow - elapsed;
const observedCount = ctx.news.totalCount; // 109
const ratePerHour = observedCount / elapsed;
const projectedAdditional = ratePerHour * hoursRemaining;
const projectedTotal = observedCount + projectedAdditional;

// Uncertainty model:
// - Poisson variance from remaining period: projectedAdditional
// - Extra regime uncertainty (30%): add ~20% variance on top
// - Total sigma empirically ~18-22 for 1-week tweet counts
const poissonSigma = Math.sqrt(projectedAdditional);
const regimeNoise = projectedTotal * 0.08; // 8% regime uncertainty
const totalSigma = Math.sqrt(poissonSigma * poissonSigma + regimeNoise * regimeNoise);

const mu = projectedTotal;
const sigma = totalSigma;

// P(a <= X <= b) under normal(mu, sigma)
const pRange = (a, b) => normCDF((b - mu) / sigma) - normCDF((a - mu) / sigma);
const pAbove = (a) => 1 - normCDF((a - mu) / sigma);

// Build probability estimates per market question
const estimates = {
  "Will Elon Musk post 0-19 tweets from April 17 to April 24, 2026?":   pRange(0, 19.5),
  "Will Elon Musk post 20-39 tweets from April 17 to April 24, 2026?":  pRange(19.5, 39.5),
  "Will Elon Musk post 40-59 tweets from April 17 to April 24, 2026?":  pRange(39.5, 59.5),
  "Will Elon Musk post 60-79 tweets from April 17 to April 24, 2026?":  pRange(59.5, 79.5),
  "Will Elon Musk post 80-99 tweets from April 17 to April 24, 2026?":  pRange(79.5, 99.5),
  "Will Elon Musk post 100-119 tweets from April 17 to April 24, 2026?": pRange(99.5, 119.5),
  "Will Elon Musk post 120-139 tweets from April 17 to April 24, 2026?": pRange(119.5, 139.5),
  "Will Elon Musk post 140-159 tweets from April 17 to April 24, 2026?": pRange(139.5, 159.5),
  "Will Elon Musk post 160-179 tweets from April 17 to April 24, 2026?": pRange(159.5, 179.5),
  "Will Elon Musk post 180-199 tweets from April 17 to April 24, 2026?": pRange(179.5, 199.5),
  "Will Elon Musk post 200-219 tweets from April 17 to April 24, 2026?": pRange(199.5, 219.5),
  "Will Elon Musk post 220-239 tweets from April 17 to April 24, 2026?": pRange(219.5, 239.5),
  "Will Elon Musk post 240-259 tweets from April 17 to April 24, 2026?": pRange(239.5, 259.5),
  "Will Elon Musk post 260-279 tweets from April 17 to April 24, 2026?": pRange(259.5, 279.5),
  "Will Elon Musk post 280-299 tweets from April 17 to April 24, 2026?": pRange(279.5, 299.5),
  "Will Elon Musk post 300-319 tweets from April 17 to April 24, 2026?": pRange(299.5, 319.5),
  "Will Elon Musk post 320-339 tweets from April 17 to April 24, 2026?": pRange(319.5, 339.5),
  "Will Elon Musk post 340-359 tweets from April 17 to April 24, 2026?": pRange(339.5, 359.5),
  "Will Elon Musk post 360-379 tweets from April 17 to April 24, 2026?": pRange(359.5, 379.5),
  "Will Elon Musk post 380-399 tweets from April 17 to April 24, 2026?": pRange(379.5, 399.5),
  "Will Elon Musk post 400-419 tweets from April 17 to April 24, 2026?": pRange(399.5, 419.5),
  "Will Elon Musk post 420-439 tweets from April 17 to April 24, 2026?": pRange(419.5, 439.5),
  "Will Elon Musk post 440-459 tweets from April 17 to April 24, 2026?": pRange(439.5, 459.5),
  "Will Elon Musk post 460-479 tweets from April 17 to April 24, 2026?": pRange(459.5, 479.5),
  "Will Elon Musk post 480-499 tweets from April 17 to April 24, 2026?": pRange(479.5, 499.5),
  "Will Elon Musk post 500-519 tweets from April 17 to April 24, 2026?": pRange(499.5, 519.5),
  "Will Elon Musk post 520-539 tweets from April 17 to April 24, 2026?": pRange(519.5, 539.5),
  "Will Elon Musk post 540-559 tweets from April 17 to April 24, 2026?": pRange(539.5, 559.5),
  "Will Elon Musk post 560-579 tweets from April 17 to April 24, 2026?": pRange(559.5, 579.5),
  "Will Elon Musk post 580+ tweets from April 17 to April 24, 2026?":    pAbove(579.5),
};

const result = ctx.markets.map((market) => {
  try {
    if (market.closed || market.hoursToExpiry < 0) {
      return { question: market.question, decision: "hold", reason: "已结算/过期" };
    }
    const mCtx = { market, timing: ctx.timing };
    const pYes = estimates[market.question] ?? 0.5;
    const probs = ctx.helpers.binaryProbsFromYesProb(mCtx, pYes);
    const edges = ctx.helpers.edgeFromProbs(probs, mCtx);
    const best = edges[0].edge >= edges[1].edge ? edges[0] : edges[1];
    const decision = best.edge >= THRESHOLD ? "buy" : "hold";
    return {
      question: market.question,
      decision,
      side: best.label,
      fairPrice: +pYes.toFixed(4),
      marketPrice: best.marketPrice,
      edge: +best.edge.toFixed(4),
      pYes: +pYes.toFixed(4),
    };
  } catch (err) {
    return { question: market.question, decision: "hold", reason: String(err) };
  }
});

// Append model metadata for reporting
result._meta = { mu: +mu.toFixed(1), sigma: +sigma.toFixed(1), elapsed: +elapsed.toFixed(1), observedCount, ratePerHour: +ratePerHour.toFixed(3) };
return result;
